-- Core teacher-led lessons seed for Bright Virtual School
-- Safe to rerun. Refreshes only rows tagged seed_pack = core_teacher_lessons_v1.

ALTER TYPE public.lesson_stage_type ADD VALUE IF NOT EXISTS 'blackboard' BEFORE 'concept';


WITH s AS (
  SELECT subjects.id, subjects.code AS subject_code, classes.code AS class_code
  FROM public.subjects
  JOIN public.classes ON classes.id = subjects.class_id
  JOIN public.boards ON boards.id = classes.board_id
  WHERE boards.code = 'TSB'
)
SELECT s.id, v.unit_code, v.title, v.description, v.sort_order, '{"seed_pack":"core_teacher_lessons_v1"}'::jsonb
FROM s
JOIN (VALUES
('CLASS1','MATH','ADDITION','{"en": "Addition", "hi": "Addition", "te": "Addition"}'::jsonb,'{"en": "Addition"}'::jsonb,1),
('CLASS1','MATH','SUBTRACTION','{"en": "Subtraction", "hi": "Subtraction", "te": "Subtraction"}'::jsonb,'{"en": "Subtraction"}'::jsonb,2),
('CLASS1','MATH','COMPARISON','{"en": "Number Comparison", "hi": "Number Comparison", "te": "Number Comparison"}'::jsonb,'{"en": "Number Comparison"}'::jsonb,3),
('CLASS1','MATH','ORDERING','{"en": "Ordering Numbers", "hi": "Ordering Numbers", "te": "Ordering Numbers"}'::jsonb,'{"en": "Ordering Numbers"}'::jsonb,4),
('CLASS1','MATH','PLACE_VALUE','{"en": "Place Value", "hi": "Place Value", "te": "Place Value"}'::jsonb,'{"en": "Place Value"}'::jsonb,5),
('CLASS1','ENGLISH','PHONICS','{"en": "Phonics", "hi": "Phonics", "te": "Phonics"}'::jsonb,'{"en": "Phonics"}'::jsonb,6),
('CLASS1','ENGLISH','CVC','{"en": "CVC Words", "hi": "CVC Words", "te": "CVC Words"}'::jsonb,'{"en": "CVC Words"}'::jsonb,7),
('CLASS1','ENGLISH','SIGHT_WORDS','{"en": "Sight Words", "hi": "Sight Words", "te": "Sight Words"}'::jsonb,'{"en": "Sight Words"}'::jsonb,8),
('CLASS1','TELUGU','GUNINTHALU','{"en": "Guninthalu", "hi": "Guninthalu", "te": "Guninthalu"}'::jsonb,'{"en": "Guninthalu"}'::jsonb,9),
('CLASS1','HINDI','MATRAS','{"en": "Matras", "hi": "Matras", "te": "Matras"}'::jsonb,'{"en": "Matras"}'::jsonb,10),
('CLASS1','EVS','MY_FAMILY','{"en": "My Family", "hi": "My Family", "te": "My Family"}'::jsonb,'{"en": "My Family"}'::jsonb,11),
('CLASS1','EVS','MY_HOME','{"en": "My Home", "hi": "My Home", "te": "My Home"}'::jsonb,'{"en": "My Home"}'::jsonb,12),
('CLASS1','EVS','MY_SCHOOL','{"en": "My School", "hi": "My School", "te": "My School"}'::jsonb,'{"en": "My School"}'::jsonb,13)
) AS v(class_code, subject_code, unit_code, title, description, sort_order)
  ON v.class_code = s.class_code AND v.subject_code = s.subject_code
ON CONFLICT (subject_id, code) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, metadata=public.units.metadata || EXCLUDED.metadata;


WITH u AS (
  SELECT units.id, units.code AS unit_code, subjects.code AS subject_code, classes.code AS class_code
  FROM public.units
  JOIN public.subjects ON subjects.id = units.subject_id
  JOIN public.classes ON classes.id = subjects.class_id
  JOIN public.boards ON boards.id = classes.board_id
  WHERE boards.code = 'TSB'
)
SELECT u.id, v.lesson_code, v.title, v.description, 'mixed'::public.lesson_type, v.minutes, v.sort_order,
       jsonb_build_object('teacher_led', true, 'seed_pack', 'core_teacher_lessons_v1'),
       '{"seed_pack":"core_teacher_lessons_v1","teacher_led":true}'::jsonb,
       true
FROM u
JOIN (VALUES
('CLASS1','MATH','ADDITION','ADDITION_OBJECTS_TEACHER','{"en": "Addition Using Objects", "hi": "Addition Using Objects", "te": "Addition Using Objects"}'::jsonb,'{"en": "Learn addition using apples, stars and real objects.", "hi": "Learn addition using apples, stars and real objects.", "te": "Learn addition using apples, stars and real objects."}'::jsonb,15,2),
('CLASS1','MATH','ADDITION','SINGLE_DIGIT_ADDITION','{"en": "Single Digit Addition", "hi": "Single Digit Addition", "te": "Single Digit Addition"}'::jsonb,'{"en": "Add single digit numbers with simple sums.", "hi": "Add single digit numbers with simple sums.", "te": "Add single digit numbers with simple sums."}'::jsonb,15,3),
('CLASS1','MATH','ADDITION','ADDITION_WORD_PROBLEMS','{"en": "Addition Word Problems", "hi": "Addition Word Problems", "te": "Addition Word Problems"}'::jsonb,'{"en": "Understand simple addition stories.", "hi": "Understand simple addition stories.", "te": "Understand simple addition stories."}'::jsonb,15,4),
('CLASS1','MATH','SUBTRACTION','SUBTRACTION_INTRO','{"en": "Introduction to Subtraction", "hi": "Introduction to Subtraction", "te": "Introduction to Subtraction"}'::jsonb,'{"en": "Learn that subtraction means taking away.", "hi": "Learn that subtraction means taking away.", "te": "Learn that subtraction means taking away."}'::jsonb,15,1),
('CLASS1','MATH','SUBTRACTION','SUBTRACTION_OBJECTS','{"en": "Subtraction Using Objects", "hi": "Subtraction Using Objects", "te": "Subtraction Using Objects"}'::jsonb,'{"en": "Use objects to subtract.", "hi": "Use objects to subtract.", "te": "Use objects to subtract."}'::jsonb,15,2),
('CLASS1','MATH','SUBTRACTION','SINGLE_DIGIT_SUBTRACTION','{"en": "Single Digit Subtraction", "hi": "Single Digit Subtraction", "te": "Single Digit Subtraction"}'::jsonb,'{"en": "Subtract single digit numbers.", "hi": "Subtract single digit numbers.", "te": "Subtract single digit numbers."}'::jsonb,15,3),
('CLASS1','MATH','COMPARISON','BIGGER_SMALLER_NUMBERS','{"en": "Bigger and Smaller Numbers", "hi": "Bigger and Smaller Numbers", "te": "Bigger and Smaller Numbers"}'::jsonb,'{"en": "Compare two numbers.", "hi": "Compare two numbers.", "te": "Compare two numbers."}'::jsonb,15,1),
('CLASS1','MATH','ORDERING','BEFORE_AFTER_NUMBERS','{"en": "Before and After Numbers", "hi": "Before and After Numbers", "te": "Before and After Numbers"}'::jsonb,'{"en": "Find numbers before and after.", "hi": "Find numbers before and after.", "te": "Find numbers before and after."}'::jsonb,15,1),
('CLASS1','MATH','PLACE_VALUE','TENS_ONES','{"en": "Place Value: Tens and Ones", "hi": "Place Value: Tens and Ones", "te": "Place Value: Tens and Ones"}'::jsonb,'{"en": "Understand tens and ones.", "hi": "Understand tens and ones.", "te": "Understand tens and ones."}'::jsonb,15,1),
('CLASS1','MATH','COMPARISON','NUMBER_COMPARISON','{"en": "Number Comparison", "hi": "Number Comparison", "te": "Number Comparison"}'::jsonb,'{"en": "Use >, < and =.", "hi": "Use >, < and =.", "te": "Use >, < and =."}'::jsonb,15,2),
('CLASS1','ENGLISH','PHONICS','LETTER_SOUNDS','{"en": "Letter Sounds", "hi": "Letter Sounds", "te": "Letter Sounds"}'::jsonb,'{"en": "Hear and say letter sounds.", "hi": "Hear and say letter sounds.", "te": "Hear and say letter sounds."}'::jsonb,15,1),
('CLASS1','ENGLISH','PHONICS','SOUND_A','{"en": "Sound of A", "hi": "Sound of A", "te": "Sound of A"}'::jsonb,'{"en": "Learn A sound words.", "hi": "Learn A sound words.", "te": "Learn A sound words."}'::jsonb,15,2),
('CLASS1','ENGLISH','PHONICS','SOUND_E','{"en": "Sound of E", "hi": "Sound of E", "te": "Sound of E"}'::jsonb,'{"en": "Learn E sound words.", "hi": "Learn E sound words.", "te": "Learn E sound words."}'::jsonb,15,3),
('CLASS1','ENGLISH','CVC','CVC_WORDS_INTRO','{"en": "CVC Words", "hi": "CVC Words", "te": "CVC Words"}'::jsonb,'{"en": "Read consonant-vowel-consonant words.", "hi": "Read consonant-vowel-consonant words.", "te": "Read consonant-vowel-consonant words."}'::jsonb,15,1),
('CLASS1','ENGLISH','SIGHT_WORDS','SIGHT_WORDS_SIMPLE','{"en": "Simple Sight Words", "hi": "Simple Sight Words", "te": "Simple Sight Words"}'::jsonb,'{"en": "Read common sight words.", "hi": "Read common sight words.", "te": "Read common sight words."}'::jsonb,15,1),
('CLASS1','TELUGU','GUNINTHALU','GUNINTHALU_INTRO','{"en": "Guninthalu Introduction", "hi": "Guninthalu Introduction", "te": "Guninthalu Introduction"}'::jsonb,'{"en": "Learn how vowel signs change consonants.", "hi": "Learn how vowel signs change consonants.", "te": "Learn how vowel signs change consonants."}'::jsonb,15,1),
('CLASS1','TELUGU','GUNINTHALU','KA_FAMILY','{"en": "క Family", "hi": "క Family", "te": "క Family"}'::jsonb,'{"en": "Practice క guninthalu.", "hi": "Practice క guninthalu.", "te": "Practice క guninthalu."}'::jsonb,15,2),
('CLASS1','TELUGU','GUNINTHALU','GA_FAMILY','{"en": "గ Family", "hi": "గ Family", "te": "గ Family"}'::jsonb,'{"en": "Practice గ guninthalu.", "hi": "Practice గ guninthalu.", "te": "Practice గ guninthalu."}'::jsonb,15,3),
('CLASS1','HINDI','MATRAS','MATRAS_INTRO','{"en": "Matras Introduction", "hi": "Matras Introduction", "te": "Matras Introduction"}'::jsonb,'{"en": "Learn Hindi vowel signs.", "hi": "Learn Hindi vowel signs.", "te": "Learn Hindi vowel signs."}'::jsonb,15,1),
('CLASS1','HINDI','MATRAS','AA_MATRA','{"en": "ा Matra", "hi": "ा Matra", "te": "ा Matra"}'::jsonb,'{"en": "Practice आ matra.", "hi": "Practice आ matra.", "te": "Practice आ matra."}'::jsonb,15,2),
('CLASS1','HINDI','MATRAS','I_MATRA','{"en": "ि Matra", "hi": "ि Matra", "te": "ि Matra"}'::jsonb,'{"en": "Practice इ matra.", "hi": "Practice इ matra.", "te": "Practice इ matra."}'::jsonb,15,3),
('CLASS1','EVS','MY_FAMILY','FAMILY_MEMBERS','{"en": "Family Members", "hi": "Family Members", "te": "Family Members"}'::jsonb,'{"en": "Learn about family members.", "hi": "Learn about family members.", "te": "Learn about family members."}'::jsonb,15,1),
('CLASS1','EVS','MY_HOME','MY_HOME','{"en": "My Home", "hi": "My Home", "te": "My Home"}'::jsonb,'{"en": "Learn about home and rooms.", "hi": "Learn about home and rooms.", "te": "Learn about home and rooms."}'::jsonb,15,1),
('CLASS1','EVS','MY_SCHOOL','MY_SCHOOL','{"en": "My School", "hi": "My School", "te": "My School"}'::jsonb,'{"en": "Learn about school.", "hi": "Learn about school.", "te": "Learn about school."}'::jsonb,15,1)
) AS v(class_code, subject_code, unit_code, lesson_code, title, description, minutes, sort_order)
  ON v.class_code = u.class_code AND v.subject_code = u.subject_code AND v.unit_code = u.unit_code
ON CONFLICT (unit_id, code) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, estimated_minutes=EXCLUDED.estimated_minutes, sort_order=EXCLUDED.sort_order, content=EXCLUDED.content, metadata=public.lessons.metadata || EXCLUDED.metadata, is_published=true;


DELETE FROM public.lesson_stages
WHERE lesson_id IN (
  SELECT id FROM public.lessons WHERE code IN ('ADDITION_OBJECTS_TEACHER', 'SINGLE_DIGIT_ADDITION', 'ADDITION_WORD_PROBLEMS', 'SUBTRACTION_INTRO', 'SUBTRACTION_OBJECTS', 'SINGLE_DIGIT_SUBTRACTION', 'BIGGER_SMALLER_NUMBERS', 'BEFORE_AFTER_NUMBERS', 'TENS_ONES', 'NUMBER_COMPARISON', 'LETTER_SOUNDS', 'SOUND_A', 'SOUND_E', 'CVC_WORDS_INTRO', 'SIGHT_WORDS_SIMPLE', 'GUNINTHALU_INTRO', 'KA_FAMILY', 'GA_FAMILY', 'MATRAS_INTRO', 'AA_MATRA', 'I_MATRA', 'FAMILY_MEMBERS', 'MY_HOME', 'MY_SCHOOL') AND metadata->>'seed_pack' = 'core_teacher_lessons_v1'
);


